def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    root = etree.fromstring(xml_data)
    student_element = root.xpath(f"//student[username='{username}' and password='{password}']")[0] if root.xpath(f"//student[username='{username}' and password='{password}']") else None
    if not student_element:
        return None
    return {
        'name': student_element.find('name').text,
        'citizenship': student_element.find('citizenship').text,
        'age': student_element.find('age').text
    }

